import json
from datetime import datetime, timezone
from pathlib import Path
rows = []
path = Path('/var/log/platform/mutation-audit.jsonl')
if path.exists():
    for line in path.read_text().splitlines():
        try:
            item = json.loads(line)
        except json.JSONDecodeError:
            continue
        if item.get('surface') != 'falco':
            continue
        if 'LV3 Falco smoke marker execution' not in str(item.get('target')):
            continue
        ts_epoch = None
        ts_value = item.get('ts')
        if isinstance(ts_value, str):
            ts_epoch = int(datetime.fromisoformat(ts_value.replace('Z', '+00:00')).astimezone(timezone.utc).timestamp())
        if ts_epoch is not None and ts_epoch < 1775080176:
            continue
        rows.append(item)
print(json.dumps(rows[-50:], sort_keys=True))
INNER
